            const canvas = document.createElement('canvas');
            canvas.width = 600;
            canvas.height = 400;
            const ctx = canvas.getContext('2d');

            // 背景渐变
            const gradient = ctx.createLinearGradient(0, 0, 0, 400);
            gradient.addColorStop(0, '#1a1a2e');
            gradient.addColorStop(0.5, '#16213e');
            gradient.addColorStop(1, '#0f3460');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, 0, 600, 400);

            // 边框
            ctx.strokeStyle = '#f5af19';
            ctx.lineWidth = 4;
            ctx.strokeRect(10, 10, 580, 380);

            // 标题
            ctx.fillStyle = '#f5af19';
            ctx.font = 'bold 36px "Microsoft YaHei", sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('🔔 编钟模拟器', 300, 70);

            // 分隔线
            ctx.strokeStyle = 'rgba(245, 175, 25, 0.3)';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(100, 90);
            ctx.lineTo(500, 90);
            ctx.stroke();

            // 演奏信息
            ctx.fillStyle = '#fff';
            ctx.font = '24px "Microsoft YaHei", sans-serif';
            ctx.fillText(recording.name, 300, 140);

            const sideCount = recording.notes.filter(n => n.isSide).length;
            const zhengCount = recording.notes.length - sideCount;

            ctx.font = '18px "Microsoft YaHei", sans-serif';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
            ctx.fillText(`⏱️ ${recording.duration}秒 · 🎵 ${recording.notes.length}音(正${zhengCount}/侧${sideCount})`, 300, 175);
            ctx.fillText(`📅 ${recording.date}`, 300, 205);

            // 提示文字
            ctx.fillStyle = '#00d2d3';
            ctx.font = '20px "Microsoft YaHei", sans-serif';
            ctx.fillText('扫码收听我的编钟演奏', 300, 260);


