        // 统一编钟动画效果
        function playBellAnimation(bellElement, isSide = false) {
            // 添加强化动画
            bellElement.classList.add('bell-swing-strong');
            bellElement.classList.add('bell-glow');
            bellElement.classList.add('bell-playing');

            // 击槌动画
            const mallet = bellElement.querySelector('.mallet-hit');
            if (mallet) {
                mallet.textContent = isSide ? '🔨·' : '·🔨';
                mallet.classList.add('show');
                setTimeout(() => mallet.classList.remove('show'), 200);
            }

            // 移除动画类
            setTimeout(() => {
                bellElement.classList.remove('bell-swing-strong');
                bellElement.classList.remove('bell-glow');
