arguments.new_string:
/* v1.10.2: 琶音器面板专业模式效果 - 暗红木纹风 */
.pro-mode-panel {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: 
        linear-gradient(180deg, rgba(60,30,20,0.98) 0%, rgba(40,20,15,0.98) 100%),
        repeating-linear-gradient(90deg, 
            rgba(139,90,43,0.15) 0px, 
            rgba(139,90,43,0.05) 2px,
            transparent 2px,
            transparent 8px
        );
    border-top: 3px solid #8b5a2b;
    box-shadow: 
        0 -5px 30px rgba(0,0,0,0.8),
        inset 0 2px 10px rgba(0,0,0,0.5);
    padding: 12px 20px;
    z-index: 100;
    display: none;
    flex-direction: row;
    align-items: center;
    justify-content: center;
    gap: 20px;
    height: 110px;
    overflow: hidden;
}

.pro-mode-panel.active {
    display: flex;
    animation: panelSlideUp 0.4s ease-out;
}

@keyframes panelSlideUp {
    0% { transform: translateY(100%); }
    100% { transform: translateY(0); }
}

/* 琶音器面板内木纹纹理 */
.pro-mode-panel::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-image: 
        repeating-linear-gradient(0deg, 
            transparent 0px,
            transparent 2px,
            rgba(60,30,20,0.3) 2px,
            rgba(60,30,20,0.3) 4px
        );
    pointer-events: none;
    opacity: 0.6;
}

/* STUDIO MODE 标识 - 面板内 */
.pro-mode-panel::after {
    content: '● STUDIO MODE';
    position: absolute;
    top: 8px;
    right: 15px;
    color: #f5af19;
    font-size: 10px;
    font-weight: bold;
    letter-spacing: 3px;
    text-shadow: 0 0 8px rgba(245, 175, 25, 0.6);
    animation: studioPulse 2s ease-in-out infinite;
}

@keyframes studioPulse {
    0%, 100% { opacity: 0.7; text-shadow: 0 0 5px rgba(245, 175, 25, 0.4); }
    50% { opacity: 1; text-shadow: 0 0 15px rgba(245, 175, 25, 0.8), 0 0 25px rgba(245, 175, 25, 0.4); }
}

/* VU表 - 放在面板左侧 */
.vu-meter {
    position: relative;
    width: 100px;
    height: 50px;
    background: linear-gradient(180deg, #1a0f0a, #0d0805);
    border: 2px solid #5a3a25;
    border-radius: 3px;
    display: flex;
    align-items: flex-end;
    justify-content: center;
    gap: 3px;
    padding: 6px 8px;
    box-shadow: 
        inset 0 0 15px rgba(0,0,0,0.9),
        0 2px 8px rgba(0,0,0,0.5);
    z-index: 10;
}

.vu-meter .vu-segment {
    width: 6px;
    height: 35px;
    background: linear-gradient(180deg, 
        #3a2a20 0%, 
        #1a1008 100%
    );
    border-radius: 1px;
    transition: all 0.15s;
}

.vu-meter .vu-segment.active {
    background: linear-gradient(180deg, 
        #f5af19 0%, 
        #c47a0f 50%,
        #8b5a2b 100%
    );
    box-shadow: 0 0 10px rgba(245, 175, 25, 0.7);
}

.vu-meter .vu-segment.peak {
    background: linear-gradient(180deg, 
        #ff6644 0%, 
        #cc3322 100%
    );
    box-shadow: 0 0 12px rgba(255, 100, 68, 0.8);
}

/* 频谱条 - 放在面板中央 */
.spectrum-bar {
    display: flex;
    gap: 4px;
    align-items: flex-end;
    height: 50px;
    z-index: 10;
}

.spectrum-bar .bar {
    width: 6px;
    background: linear-gradient(180deg, #f5af19, #8b4513);
    border-radius: 3px;
    opacity: 0.9;
    animation: spectrumDance 0.4s ease-in-out infinite alternate;
    box-shadow: 0 0 8px rgba(245, 175, 25, 0.4);
}

.spectrum-bar .bar:nth-child(1) { height: 25px; animation-delay: 0s; }
.spectrum-bar .bar:nth-child(2) { height: 40px; animation-delay: 0.1s; }
.spectrum-bar .bar:nth-child(3) { height: 30px; animation-delay: 0.15s; }
.spectrum-bar .bar:nth-child(4) { height: 45px; animation-delay: 0.05s; }
.spectrum-bar .bar:nth-child(5) { height: 35px; animation-delay: 0.2s; }
.spectrum-bar .bar:nth-child(6) { height: 40px; animation-delay: 0.1s; }
.spectrum-bar .bar:nth-child(7) { height: 28px; animation-delay: 0.25s; }

@keyframes spectrumDance {
    0% { transform: scaleY(0.4); opacity: 0.6; }
    100% { transform: scaleY(1); opacity: 1; }
}

/* 移除body上的效果 */
body.pro-mode-active {
    /* 不再改变整个页面背景 */
}

body.pro-mode-active::before,
body.pro-mode-active::after {
    display: none;
}

