    gap: 4px;
    align-items: flex-end;
    height: 50px;
    z-index: 10;
}

.spectrum-bar .bar {
    width: 6px;
    background: linear-gradient(180deg, #f5af19, #8b4513);
    border-radius: 3px;
    opacity: 0.9;
    /* 默认安静状态 */
    height: 8px !important;
    transform: scaleY(1);
    animation: none;
    transition: all 0.2s ease-out;
    box-shadow: 0 0 5px rgba(245, 175, 25, 0.2);
}

