        // v1.5.7: 维护正在播放的音频源数组（用于单实例限制）
        let activeSources = [];

        function playArpeggioPattern(notes) {
            const now = audioContext.currentTime;

            // v1.5.7: 单实例锁 - 停止之前所有正在播放的音频源
            activeSources.forEach(source => {
                try {
                    source.stop();
                } catch (e) {
                    // 忽略已经停止的源
                }
            });
            activeSources = [];

            // 清理之前的定时器
            arpeggiatorTimeouts.forEach(id => clearTimeout(id));
            arpeggiatorTimeouts = [];

            // v1.6.4: 清理之前的倒计时显示
            document.querySelectorAll('.chord-btn .countdown').forEach(el => el.remove());

            // v1.5.5 修复：4个音都使用传入的 notes，不再固定最后一个音为 C3
            const eighthNoteDuration = EIGHTH_NOTE_MS / 1000; // 8分音符秒数 (0.6s)

            // v1.6.7: 创建 SVG 燃尽环
            if (activeChordBtn) {
                // 移除旧的燃尽环
                const oldRing = activeChordBtn.querySelector('.burn-ring');
                if (oldRing) oldRing.remove();

                // 创建新的燃尽环
                const ring = document.createElement('div');
                ring.className = 'burn-ring';
                ring.innerHTML = `
                    <svg viewBox="0 0 60 60">
                        <rect x="2" y="2" width="56" height="56" rx="8" ry="8" />
                    </svg>
                `;
                activeChordBtn.appendChild(ring);

                // 触发动画
                requestAnimationFrame(() => {
                    activeChordBtn.classList.add('active');
                });
            }

            // 播放4个音（每个8分音符）
            for (let i = 0; i < 4; i++) {
                const playTime = now + (i * eighthNoteDuration);
                const freq = notes[i];

                // 确保音频缓冲已生成
                if (!audioBufferCache[freq]) {
                    audioBufferCache[freq] = generateBellBuffer(freq);
                }

                const source = audioContext.createBufferSource();
                source.buffer = audioBufferCache[freq];
                source.connect(masterGain);
                source.start(playTime);

                // v1.5.7: 跟踪这个音频源
                activeSources.push(source);
            }

            // 4拍后重置状态（4个8分音符占2拍 + 延音踏板2拍 = 总4拍）
            const resetTimeout = setTimeout(() => {
                isArpeggiatorPlaying = false;
                if (activeChordBtn) {
                    activeChordBtn.classList.remove('active');
                    // v1.6.7: 移除燃尽环
                    const ring = activeChordBtn.querySelector('.burn-ring');
                    if (ring) ring.remove();
                }
            }, BEAT_MS * 4); // 4拍 = 4800ms @ BPM 50

            arpeggiatorTimeouts.push(resetTimeout);
        }

