/* v1.10.4: 专业模式全局暖色背景 */
body.pro-mode-active {
    background: linear-gradient(135deg, #2a1518 0%, #1e0f12 50%, #150a0d 100%);
}

/* v1.10.4: 专业模式面板 */
.pro-mode-panel {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: 
        linear-gradient(180deg, rgba(90,30,30,0.98) 0%, rgba(60,20,20,0.98) 50%, rgba(40,15,15,0.98) 100%),
        repeating-linear-gradient(90deg, 
            rgba(139,69,69,0.2) 0px, 
            rgba(160,82,82,0.1) 3px,
            transparent 3px,
            transparent 12px
        ),
        repeating-linear-gradient(0deg,
            rgba(80,30,30,0.4) 0px,
            rgba(80,30,30,0.4) 1px,
            transparent 1px,
            transparent 20px
        );
    border-top: 3px solid #a0524d;
    box-shadow: 
        0 -5px 30px rgba(0,0,0,0.8),
        inset 0 2px 10px rgba(0,0,0,0.5);
    padding: 15px 25px;
    z-index: 100;
    display: none;
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
    gap: 20px;
    height: 110px;
    overflow: hidden;
}

.pro-mode-panel.active {
    display: flex;
    animation: panelSlideUp 0.4s ease-out;
}

@keyframes panelSlideUp {
    0% { transform: translateY(100%); }
    100% { transform: translateY(0); }
}

/* 左侧面板 */
.pro-mode-left {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: 10px;
    z-index: 10;
    min-width: 120px;
}

/* 右侧面板 */
.pro-mode-right {
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    gap: 8px;
    z-index: 10;
    flex: 1;
}

/* 右侧BPM和频谱条容器 */
.pro-mode-spectrum-area {
    display: flex;
    align-items: flex-end;
    gap: 15px;
    width: 100%;
    justify-content: flex-end;
}

/* CLOSE按钮 - 木纹风格 */
.close-btn {
    width: 50px;
    height: 50px;
    border-radius: 50%;
    background: 
        linear-gradient(145deg, rgba(139,90,43,0.8), rgba(101,67,33,0.9)),
        repeating-linear-gradient(45deg, 
            rgba(101,67,33,0.3) 0px,
            rgba(139,90,43,0.2) 2px,
            transparent 2px,
            transparent 6px
        );
    border: 2px solid rgba(210,180,140,0.6);
    color: #f5deb3;
    font-size: 0.7rem;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.2s;
    display: flex;
    align-items: center;
    justify-content: center;
    text-shadow: 0 1px 2px rgba(0,0,0,0.5);
    box-shadow: 
        0 4px 10px rgba(0,0,0,0.4),
        inset 0 1px 3px rgba(255,255,255,0.1);
}

.close-btn:hover {
    background: 
        linear-gradient(145deg, rgba(160,100,50,0.9), rgba(120,80,40,0.95)),
        repeating-linear-gradient(45deg, 
            rgba(120,80,40,0.3) 0px,
            rgba(160,100,50,0.2) 2px,
            transparent 2px,
            transparent 6px
        );
    border-color: rgba(245,222,179,0.8);
    transform: translateY(-2px);
    box-shadow: 
        0 6px 15px rgba(0,0,0,0.5),
        0 0 15px rgba(245,175,25,0.2),
        inset 0 1px 3px rgba(255,255,255,0.15);
}

.close-btn:active {
    transform: translateY(0);
    box-shadow: 
        0 2px 5px rgba(0,0,0,0.4),
        inset 0 2px 5px rgba(0,0,0,0.3);
}

/* BPM - 放在频谱条左侧 */
.bpm-display {
    background: rgba(245, 175, 25, 0.1);
    padding: 6px 12px;
    border-radius: 15px;
    border: 1px solid rgba(245, 175, 25, 0.4);
    font-size: 0.8rem;
    font-weight: bold;
    color: #f5af19;
    text-shadow: 0 0 5px rgba(245, 175, 25, 0.3);
    white-space: nowrap;
}

