/* 频谱条 - 默认安静 */
.spectrum-bar {
    display: flex;
    gap: 5px;
    align-items: flex-end;
    height: 55px;
    z-index: 10;
    flex: 1;
    max-width: 200px;
}

.spectrum-bar .bar {
    width: 8px;
    background: linear-gradient(180deg, #f5af19, #8b4513);
    border-radius: 4px;
    opacity: 0.9;
    /* 默认安静状态 */
    height: 6px !important;
    transform: scaleY(1);
    animation: none;
    transition: all 0.15s ease-out;
    box-shadow: 0 0 5px rgba(245, 175, 25, 0.2);
}

/* 活跃状态 - 点击和弦时，更激烈 */
.spectrum-bar.active .bar {
    animation: spectrumDance 0.3s ease-in-out infinite alternate;
}

.spectrum-bar.active .bar:nth-child(1) { height: 35px !important; animation-delay: 0s; }
.spectrum-bar.active .bar:nth-child(2) { height: 55px !important; animation-delay: 0.05s; }
.spectrum-bar.active .bar:nth-child(3) { height: 45px !important; animation-delay: 0.1s; }
.spectrum-bar.active .bar:nth-child(4) { height: 60px !important; animation-delay: 0.03s; }
.spectrum-bar.active .bar:nth-child(5) { height: 50px !important; animation-delay: 0.08s; }
.spectrum-bar.active .bar:nth-child(6) { height: 55px !important; animation-delay: 0.05s; }
.spectrum-bar.active .bar:nth-child(7) { height: 40px !important; animation-delay: 0.12s; }

@keyframes spectrumDance {
    0% { transform: scaleY(0.3); opacity: 0.7; }
    100% { transform: scaleY(1); opacity: 1; filter: brightness(1.3); }
}

