/* 频谱条 - 默认就有轻微动画 */
.spectrum-bar {
    display: flex;
    gap: 4px;
    align-items: flex-end;
    height: 50px;
    z-index: 10;
}

.spectrum-bar .bar {
    width: 6px;
    background: linear-gradient(180deg, #f5af19, #8b4513);
    border-radius: 3px;
    opacity: 0.7;
    animation: spectrumIdle 1.5s ease-in-out infinite alternate;
    box-shadow: 0 0 5px rgba(245, 175, 25, 0.2);
}

/* 默认轻微动画 */
@keyframes spectrumIdle {
    0% { height: 8px; opacity: 0.5; }
    100% { height: 16px; opacity: 0.8; }
}

.spectrum-bar .bar:nth-child(1) { animation-delay: 0s; }
.spectrum-bar .bar:nth-child(2) { animation-delay: 0.2s; }
.spectrum-bar .bar:nth-child(3) { animation-delay: 0.1s; }
.spectrum-bar .bar:nth-child(4) { animation-delay: 0.3s; }
.spectrum-bar .bar:nth-child(5) { animation-delay: 0.15s; }
.spectrum-bar .bar:nth-child(6) { animation-delay: 0.25s; }
.spectrum-bar .bar:nth-child(7) { animation-delay: 0.05s; }

/* 活跃状态 - 点击和弦时，更激烈 */
.spectrum-bar.active .bar {
    animation: spectrumDance 0.3s ease-in-out infinite alternate;
}

.spectrum-bar.active .bar:nth-child(1) { animation-delay: 0s; }
.spectrum-bar.active .bar:nth-child(2) { animation-delay: 0.05s; }
.spectrum-bar.active .bar:nth-child(3) { animation-delay: 0.1s; }
.spectrum-bar.active .bar:nth-child(4) { animation-delay: 0.03s; }
.spectrum-bar.active .bar:nth-child(5) { animation-delay: 0.08s; }
.spectrum-bar.active .bar:nth-child(6) { animation-delay: 0.05s; }
.spectrum-bar.active .bar:nth-child(7) { animation-delay: 0.12s; }

@keyframes spectrumDance {
    0% { transform: scaleY(0.3); opacity: 0.7; height: 20px; }
    100% { transform: scaleY(1); opacity: 1; filter: brightness(1.3); height: 55px; }
}

