            transform: scale(0.95);
        }

        .bell-swing {
            animation: swing 0.5s cubic-bezier(0.36, 0, 0.66, -0.56);
        }

        .bell-swing-strong {
            animation: swingStrong 0.6s cubic-bezier(0.36, 0, 0.66, -0.56);
        }

        @keyframes swing {
            0% { transform: rotate(0deg); }
