function toggleProMode() {
    console.log('toggleProMode 被调用, 当前状态:', isProMode);
    isProMode = !isProMode;
    const panel = document.getElementById('proModePanel');
    const overlay = document.getElementById('proModeOverlay');
    const btn = document.getElementById('btnProMode');

    console.log('面板元素:', panel);
    console.log('按钮元素:', btn);

    if (isProMode) {
        panel.classList.add('active');
        overlay.classList.add('active');
        btn.classList.add('active');
        btn.innerHTML = '🎹 退出专业';
        // v1.10.0: 添加专业模式氛围
        document.body.classList.add('pro-mode-active');
        // v1.10.12: 专业模式打开音效
        playProModeSound(true);
        showToast('专业模式开启 - BPM 50');
    } else {
        panel.classList.remove('active');
        overlay.classList.remove('active');
        btn.classList.remove('active');
        btn.innerHTML = '🎹 专业模式';
        stopArpeggio();
        // v1.10.0: 移除专业模式氛围
        document.body.classList.remove('pro-mode-active');
        // v1.10.12: 专业模式关闭音效
        playProModeSound(false);
    }
}

// v1.10.12: 专业模式开关音效
function playProModeSound(isOpen) {
    try {
        const audioCtx = getAudioContext();
        if (!audioCtx) return;

        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();

        osc.connect(gain);
        gain.connect(audioCtx.destination);

        const now = audioCtx.currentTime;

        if (isOpen) {
            // 打开音效：上升琶音
            osc.frequency.setValueAtTime(220, now);
            osc.frequency.exponentialRampToValueAtTime(440, now + 0.15);
            gain.gain.setValueAtTime(0.3, now);
            gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        } else {
            // 关闭音效：下降音
            osc.frequency.setValueAtTime(440, now);
            osc.frequency.exponentialRampToValueAtTime(220, now + 0.15);
            gain.gain.setValueAtTime(0.3, now);
            gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        }

        osc.start(now);
        osc.stop(now + 0.25);
    } catch (e) {
        console.error('播放专业模式音效失败:', e);
    }
}

