/* 右侧区域 - STUDIO MODE + BPM + 频谱条 */
.pro-mode-right {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 5px;
    z-index: 10;
    margin-left: auto;
    height: 100%;
    justify-content: flex-start;
    position: relative;
}

/* 频谱条容器 - 固定在底部，不挤压上方元素 */
.spectrum-container {
    position: absolute;
    bottom: 10px;
    left: 50%;
    transform: translateX(-50%);
    height: 50px;
    display: flex;
    align-items: flex-end;
    justify-content: center;
}

/* STUDIO MODE - 绝对定位贴到顶部 */
.studio-badge {
    color: #f5af19;
    font-size: 1.2rem;
    font-weight: bold;
    letter-spacing: 3px;
    text-shadow: 0 0 10px rgba(245, 175, 25, 0.6);
    animation: studioPulse 2s ease-in-out infinite;
    line-height: 1;
    position: absolute;
    top: 5px;
    left: 50%;
    transform: translateX(-50%);
    white-space: nowrap;
}

